arguments.typescript:
const apis = require('./api') || {};
const { getTargetChannel, summarizeChannel } = apis;

const channel = await getTargetChannel();
const channelId = channel.channelId;

const now = new Date();
const twentyFourHoursAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const toIso = now.toISOString();
const fromIso = twentyFourHoursAgo.toISOString();

const result = await summarizeChannel({ channelId, fromIso, toIso });

return {
  channelId: result.channelId,
  fromIso: result.fromIso,
  toIso: result.toIso,
  summary: result.summary,
  topics: result.topics,
  actionItems: result.actionItems,
};

